mapper.select:
WITH picked AS (
    SELECT id FROM batch.worker_report_outbox
    WHERE tenant_id = #{tenantId}
      AND publish_status = #{statusNew} AND next_attempt_at <= #{nowEpochMillis}
    ORDER BY id ASC
    LIMIT 1
    FOR UPDATE SKIP LOCKED
)
UPDATE batch.worker_report_outbox AS o
SET publish_status = #{statusPublishing}, updated_at = #{nowEpochMillis}
FROM picked AS p
WHERE o.tenant_id = #{tenantId} AND o.id = p.id
RETURNING o.id, o.payload_json::text AS payload_json

mapper.update:
UPDATE batch.worker_report_outbox
SET publish_status = #{publishStatus}, attempt_count = #{attemptCount}, updated_at = #{updatedAt}
WHERE tenant_id = #{tenantId} AND id = #{id}

UPDATE batch.worker_report_outbox
SET attempt_count = #{attemptCount}, next_attempt_at = #{nextAttemptAt}, updated_at = #{updatedAt},
    publish_status = #{publishStatus}
WHERE tenant_id = #{tenantId} AND id = #{id}

UPDATE batch.worker_report_outbox
SET publish_status = #{statusNew}, updated_at = #{now}
WHERE publish_status = #{statusPublishing} AND updated_at < #{cutoff}

UPDATE batch.worker_report_outbox SET publish_status = #{publishStatus}, updated_at = #{now}, attempt_count =
    CASE WHEN attempt_count < #{maxAttempts} THEN #{maxAttempts} ELSE attempt_count END
WHERE tenant_id = #{tenantId} AND id = #{id}
